  maxRR?: number
}

export function RRBar({ rr, maxRR = 5 }: Props) {
  const targets = [1, 2, 3, Math.max(rr, 3.1)]
  const clampedRR = Math.min(rr, maxRR)
  const pct = (clampedRR / maxRR) * 100

  return (
    <div style={{ width: '100%' }}>
      <div
        style={{
          position: 'relative',
          height: '20px',
          background: 'rgba(255,255,255,0.05)',
