            top: 0,
            height: '100%',
            width: `${pct}%`,
            background: 'linear-gradient(90deg, rgba(76,154,255,0.3), rgba(47,203,126,0.5))',
            borderRadius: '4px',
            transition: 'width 0.3s ease',
          }}
        />
        {targets.slice(0, 3).map((t) => {
          const tp = (t / maxRR) * 100
          return (
            <div
              key={t}
              style={{
                position: 'absolute',
                left: `${tp}%`,
                top: 0,
                height: '100%',
                width: '1px',
                background: 'rgba(255,255,255,0.15)',
              }}
            />
          )
        })}
      </div>
      <div
        style={{
