import { useEffect, useState } from 'react'
import { useStore } from '../../store'
import { Button } from '../ui/Button'
import { KpiTile } from '../ui/KpiTile'
import { RRBar } from '../ui/RRBar'
import type { Signal, RiskCalcResult } from '../../types'

interface Props {
  signal: Signal
}

function calcRisk(
  balance: number,
  riskPct: number,
  entry: number,
  stop: number,
  t1: number,
  t2: number,
  t3: number,
  leverage: number,
  mult: number
): RiskCalcResult {
  const dollarRisk = balance * (riskPct / 100)
  const stopDist = Math.abs(entry - stop)
  const units = stopDist > 0 ? dollarRisk / (stopDist * mult) : 0
  const exposure = units * entry * mult
  const marginReq = leverage > 0 ? exposure / leverage : exposure
  const riskUsd = units * stopDist * mult

  function rr(tgt: number) {
    return stopDist > 0 ? Math.abs(tgt - entry) / stopDist : 0
  }

  return {
    units: Math.floor(units),
    exposure,
    margin_req: marginReq,
    risk_usd: riskUsd,
    dollar_risk: dollarRisk,
    stop_distance: stopDist,
    rr_t1: rr(t1),
    rr_t2: rr(t2),
    rr_t3: rr(t3),
    reward_t1: Math.floor(units) * Math.abs(t1 - entry) * mult,
    reward_t2: Math.floor(units) * Math.abs(t2 - entry) * mult,
    reward_t3: Math.floor(units) * Math.abs(t3 - entry) * mult,
  }
}

function fmt$(n: number) {
  return n.toLocaleString('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 })
}

export function RiskPanel({ signal }: Props) {
  const { account, setAccount, setCurrentPlan } = useStore()
  const [entry, setEntry] = useState(signal.entry)
  const [stop, setStop] = useState(signal.stop)
  const [t1, setT1] = useState(signal.t1)
  const [t2, setT2] = useState(signal.t2)
  const [t3, setT3] = useState(signal.t3)
  const [saved, setSaved] = useState(false)

  useEffect(() => {
    setEntry(signal.entry)
    setStop(signal.stop)
    setT1(signal.t1)
    setT2(signal.t2)
    setT3(signal.t3)
    setSaved(false)
  }, [signal])

  const result = calcRisk(
    account.balance,
    account.risk_pct,
    entry,
    stop,
    t1,
    t2,
    t3,
    account.leverage,
    account.cfd_mult
  )

  function savePlan() {
    setCurrentPlan({
      id: Date.now(),
      signal_id: signal.id,
      account_id: account.id,
      direction: signal.type,
      ticker: signal.ticker,
      entry,
      stop,
      t1,
      t2,
      t3,
      units: result.units,
      exposure: result.exposure,
      margin_req: result.margin_req,
      risk_pct: account.risk_pct,
      risk_usd: result.risk_usd,
      rr_t1: result.rr_t1,
      rr_t2: result.rr_t2,
      rr_t3: result.rr_t3,
      created_at: new Date().toISOString(),
      notes: '',
    })
    setSaved(true)
  }

  const NumInput = ({ label, value, onChange }: { label: string; value: number; onChange: (v: number) => void }) => (
    <div>
      <div style={{ fontSize: '11px', color: 'var(--dim)', marginBottom: '4px', fontFamily: "'IBM Plex Mono', monospace" }}>
        {label}
      </div>
      <input
        type="number"
        step="any"
        value={value}
        onChange={(e) => onChange(parseFloat(e.target.value) || 0)}
        style={{
          width: '100%',
          background: 'var(--panel)',
          border: '1px solid var(--border)',
          borderRadius: '6px',
          padding: '7px 10px',
          color: 'var(--ink)',
          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: '13px',
          outline: 'none',
        }}
        onFocus={(e) => (e.target.style.borderColor = 'var(--blue)')}
        onBlur={(e) => (e.target.style.borderColor = 'var(--border)')}
      />
    </div>
  )

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', overflowY: 'auto' }}>
      {/* Account settings */}
      <div style={{ padding: '16px 20px', borderBottom: '1px solid var(--border)' }}>
        <div
          style={{
            fontFamily: "'IBM Plex Mono', monospace",
            fontSize: '10px',
            letterSpacing: '0.12em',
            color: 'var(--dim)',
            marginBottom: '12px',
          }}
        >
          ACCOUNT
        </div>
        <div style={{ display: 'flex', gap: '10px' }}>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: '11px', color: 'var(--dim)', marginBottom: '4px', fontFamily: "'IBM Plex Mono', monospace" }}>
              BALANCE
            </div>
            <input
              type="number"
              value={account.balance}
              onChange={(e) => setAccount({ balance: parseFloat(e.target.value) || 0 })}
              style={{
                width: '100%',
                background: 'var(--panel)',
                border: '1px solid var(--border)',
                borderRadius: '6px',
                padding: '7px 10px',
                color: 'var(--ink)',
                fontFamily: "'IBM Plex Mono', monospace",
                fontSize: '13px',
                outline: 'none',
              }}
            />
          </div>
          <div style={{ width: '90px' }}>
            <div style={{ fontSize: '11px', color: 'var(--dim)', marginBottom: '4px', fontFamily: "'IBM Plex Mono', monospace" }}>
              RISK %
            </div>
            <input
              type="number"
              step="0.1"
              min="0.1"
              max="5"
              value={account.risk_pct}
              onChange={(e) => setAccount({ risk_pct: parseFloat(e.target.value) || 1 })}
              style={{
                width: '100%',
                background: 'var(--panel)',
                border: '1px solid var(--border)',
                borderRadius: '6px',
                padding: '7px 10px',
                color: 'var(--blue)',
                fontFamily: "'IBM Plex Mono', monospace",
                fontSize: '13px',
                outline: 'none',
              }}
            />
          </div>
        </div>
      </div>

      {/* Level inputs */}
      <div style={{ padding: '16px 20px', borderBottom: '1px solid var(--border)' }}>
        <div
          style={{
            fontFamily: "'IBM Plex Mono', monospace",
            fontSize: '10px',
            letterSpacing: '0.12em',
            color: 'var(--dim)',
            marginBottom: '12px',
          }}
        >
          TRADE LEVELS
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          <NumInput label="ENTRY" value={entry} onChange={setEntry} />
          <NumInput label="STOP LOSS" value={stop} onChange={setStop} />
          <NumInput label="TARGET 1" value={t1} onChange={setT1} />
          <NumInput label="TARGET 2" value={t2} onChange={setT2} />
          <NumInput label="TARGET 3" value={t3} onChange={setT3} />
        </div>
      </div>

      {/* Calculated output */}
      <div style={{ padding: '16px 20px', borderBottom: '1px solid var(--border)' }}>
        <div
          style={{
            fontFamily: "'IBM Plex Mono', monospace",
            fontSize: '10px',
            letterSpacing: '0.12em',
            color: 'var(--dim)',
            marginBottom: '14px',
          }}
        >
          POSITION SIZE
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginBottom: '16px' }}>
          <KpiTile label="UNITS" value={result.units.toLocaleString()} accent />
          <KpiTile label="DOLLAR RISK" value={fmt$(result.risk_usd)} color="var(--red)" />
          <KpiTile label="EXPOSURE" value={fmt$(result.exposure)} />
          <KpiTile label="MARGIN REQ" value={fmt$(result.margin_req)} />
        </div>

        <div
          style={{
            fontFamily: "'IBM Plex Mono', monospace",
            fontSize: '10px',
            letterSpacing: '0.12em',
            color: 'var(--dim)',
            marginBottom: '10px',
          }}
        >
          REWARD : RISK
        </div>
        <RRBar rr={signal.rr} />

        <div style={{ display: 'flex', flexDirection: 'column', gap: '6px', marginTop: '14px' }}>
          {[
            { label: 'T1 reward', value: fmt$(result.reward_t1), rr: result.rr_t1 },
            { label: 'T2 reward', value: fmt$(result.reward_t2), rr: result.rr_t2 },
            { label: 'T3 reward', value: fmt$(result.reward_t3), rr: result.rr_t3 },
          ].map(({ label, value, rr }) => (
            <div
              key={label}
              style={{ display: 'flex', justifyContent: 'space-between', padding: '4px 0' }}
            >
              <span style={{ fontSize: '12px', color: 'var(--muted)' }}>
                {label}
                <span
                  style={{
                    fontFamily: "'IBM Plex Mono', monospace",
                    fontSize: '11px',
                    color: 'var(--dim)',
                    marginLeft: '6px',
                  }}
                >
                  ({rr.toFixed(1)}R)
                </span>
              </span>
              <span
                style={{
                  fontFamily: "'IBM Plex Mono', monospace",
                  fontSize: '12px',
                  color: 'var(--green)',
                }}
              >
                {value}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Save plan */}
      <div style={{ padding: '16px 20px' }}>
        <Button
          variant={saved ? 'confirm' : 'primary'}
          size="md"
          onClick={savePlan}
          style={{ width: '100%' }}
          disabled={saved}
        >
          {saved ? '✓ Plan saved to Journal' : `Confirm ${signal.type === 'bull' ? 'Long' : 'Short'} · ${result.units} units`}
        </Button>
      </div>
    </div>
  )
}
